SELECT *
FROM iims_integral_wiki_catalog
WHERE wiki_id = #{wikiId}
  AND doc_id = #{docId}
LIMIT 1;

SELECT *
FROM iims_integral_wiki_catalog
WHERE wiki_id = #{wikiId}
  AND doc_id IS NOT NULL
  AND id > #{catalogId}
ORDER BY id
LIMIT 1;

SELECT *
FROM iims_integral_wiki_catalog
WHERE wiki_id = #{wikiId}
AND doc_id IS NOT NULL
AND id < #{catalogId}
ORDER BY id DESC
LIMIT 1;

